head.script:
	/**
	 * 화면 초기화 작업을 수행한다.
	 * @param
	 * @return	 
	 */ 	
	scwin.initScreen = function() {
		// 화면 초기화
        comLib.initForm($p, "dataMapping");

		// 디폴트 값 설정
		scwin.setDefaultValue();

		// 데이터 조회
		scwin.retrieveOldTableList();
		scwin.retrieveNewTableList();
	};

	/**
	 * 기본값 설정
	 * @param
	 * @return
	 */
	scwin.setDefaultValue = function() {
		// 조회건수
		dmaInquireParam1.set("retCnt", "100");
		dmaInquireParam2.set("retCnt", "100");

		// 매핑컬럼 : 값(MAPPED_KEY)이 있으면 "매핑제외", 없으면 "전체"
		// 매핑제외 Checkbox의 Value에 "MAPPED_KEY" 설정
		dmaInquireParam1.set("mappedColNm", "");
		dmaInquireParam2.set("mappedColNm", "");
	};

	/**
	 * AS-IS 테이블 목록을 조회한다.
	 * @param
	 * @return	 
	 */ 
	scwin.retrieveOldTableList = function() {
		var requestData = {};

		requestData.param = {"tableList" : ["VT_ZZ_BIZ_SITE_AS"   // 사업장(면)
												, "VT_ZZ_COUPLING"   // 커플링
												, "VT_ZZ_DRAINAGE"   // 배류기위치
												, "VT_ZZ_DRAINAGE_PS"   // 배류기위치(점)
												, "VT_ZZ_FACILITY_AS"   // 시설물(면)
												, "VT_ZZ_FIREFIGHTING_PS"   // 소방시설(점)
												, "VT_ZZ_FLOWMETER_PS"   // 유량계위치(점)
												, "VT_ZZ_FLOWMETER_SPECIFICATION"   // 유량계제원												
												, "VT_ZZ_INTAKE_AS"   // 취수구(면)
												, "VT_ZZ_INVERTER"   // 인버터
												, "VT_ZZ_MANHOLE_PS"   // 맨홀(점)
												, "VT_ZZ_MOTOR"   // 모터
												, "VT_ZZ_PUMP"   // 펌프
												, "VT_ZZ_PUMP_MOTOR_PS"   // 펌프모터(점)
												, "VT_ZZ_PUMP_MOTOR_VALVE"   // 펌프모터밸브
												, "VT_ZZ_RECTIFIER"   // 정류기										
												, "VT_ZZ_RECTIFIER_PS"   // 정류기위치(점)
												, "VT_ZZ_STANDPIPE_PS"   // 스탠드파이프(점)
												, "VT_ZZ_STRUCTURES_AS"   // 건축물(면)
												, "VT_ZZ_SURGE_TANK_PS"   // 서지탱크(점)
												, "VT_ZZ_TEST_BOX"   // 측정함
												, "VT_ZZ_TEST_BOX_PS"   // 측정함위치(점)
												, "VT_ZZ_TUNNEL_AS"   // 터널(면)
												, "VT_ZZ_VALVEROOM_AS"   // 밸브실(면)
												, "VT_ZZ_VALVE_PS"   // 밸브(점)
												, "VT_ZZ_WASTE_PIPELINE"   // 폐관로 
												, "VT_ZZ_WATER_PIPELINE_LS"   // 상수관로(선)  
												]
								   };

		var option = {action : "zz/data/retrieveTableList.do"
						, reqData : requestData
						, resData : dltTableList1
						, success : "scwin.retrieveOldTableListCallBack"
						, isShowMeg : false
						};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * AS-IS 테이블 목록 CallBack을 실행한다.
	 * @param
	 * @return	 
	 */ 	
	scwin.retrieveOldTableListCallBack = function(res) {
		if (dltTableList1.getRowCount() == 0) {
			comLib.alert($p, "AS-IS 테이블의 데이터가 없습니다.");
		}
	};

	/**
	 * AS-IS 테이블의 컬럼 정보를 조회한다.
	 * @param
	 * @return	 
	 */ 	
	scwin.sbxTables1_onchange = function() {
		var tableNm = sbxTables1.getValue();

		if (tableNm != "" && tableNm != null) {	
			var requestData = {};
			requestData.param = {"tableName" : tableNm};

			var option = {action : "zz/data/retrieveTabColumns.do"
							, reqData : requestData
							, resData : dltColumns1
							, success : "scwin.sbxTables1CallBack"
							, isShowMeg : false
							};
			ajaxLib.executeAjax($p, option);
		} else {
			comLib.alert($p, "테이블명은 필수 입력 항목입니다.");
		}
	};

	/**
	 * AS-IS 테이블의 컬럼 정보 CallBack을 실행한다.
	 * @param
	 * @return	 
	 */ 	
	scwin.sbxTables1CallBack = function(res) {
		if (dltColumns1.getRowCount() > 0) {
			// 고정 컬럼 설정
			scwin.setAsisFixedColumns();

			// 컬럼 설정
			scwin.setColumnId(dltColumns1);

			// 컬럼 필터 설정 - 보이지 않는 컬럼 설정
			scwin.setAsisColumnFilter();

			// 해당 테이블의 데이터 조회
			scwin.btnInquire1_onclick();
		} else {
			comLib.alert($p, "AS-IS 테이블의 컬럼 정보가 없습니다.");
		}
	};

	/**
	 * AS-IS 고정 컬럼 설정
	 * @param
	 * @return	 
	 */ 
	scwin.setAsisFixedColumns = function() {
		// 해당 테이블에 고정 컬럼이 포함되어 있지 않으면 SelectBox를 disabled 처리
		// 지역본부
		var idx = dltColumns1.getMatchedIndex("columnName", "ROHQCD", true);
		if (idx != "" && idx != null) {
			dmaInquireParam1.set("fixColNm1", "ROHQCD");
			sbxFixCol11.setDisabled(false);	

			// 지역본부 목록 조회
			scwin.retrieveOldHeadquarterList();
		} else {
			dmaInquireParam1.set("fixColNm1", "");
			sbxFixCol11.setDisabled(true);	
		}

		// 관리부서
		idx = dltColumns1.getMatchedIndex("columnName", "MGDPCD", true);
		if (idx != "" && idx != null) {
			dmaInquireParam1.set("fixColNm2", "MGDPCD");
			sbxFixCol12.setDisabled(false);	
		} else {
			dmaInquireParam1.set("fixColNm2", "");
			sbxFixCol12.setDisabled(true);	
		}

		// 사업단계
		idx = dltColumns1.getMatchedIndex("columnName", "BZSPCD", true);
		if (idx != "" && idx != null) {
			dmaInquireParam1.set("fixColNm3", "BZSPCD");
			sbxFixCol13.setDisabled(false);	
		} else {
			dmaInquireParam1.set("fixColNm3", "");
			sbxFixCol13.setDisabled(true);	
		}

		// 계통
		idx = dltColumns1.getMatchedIndex("columnName", "CNNCD", true);
		if (idx != "" && idx != null) {
			dmaInquireParam1.set("fixColNm4", "CNNCD");
			sbxFixCol14.setDisabled(false);	
		} else {
			dmaInquireParam1.set("fixColNm4", "");
			sbxFixCol14.setDisabled(true);	
		}

		// 구간
		idx = dltColumns1.getMatchedIndex("columnName", "SCNCD", true);
		if (idx != "" && idx != null) {
			dmaInquireParam1.set("fixColNm5", "SCNCD");
			sbxFixCol15.setDisabled(false);	
		} else {
			dmaInquireParam1.set("fixColNm5", "");
			sbxFixCol15.setDisabled(true);	
		}
	};

	/**
	 * AS-IS 컬럼 필터 설정
	 * @param
	 * @return	 
	 */ 
	scwin.setAsisColumnFilter = function() {	
		// 조회 조건 컬럼 Filter 설정
		// 첫 번째 컬럼(MAPPED_KEY - 검색하면 속도 느림)과 고정(코드) 컬럼이 검색 조건에서 보이지 않도록 Filter 설정
		dltColumns1.setColumnFilter({type : "regExp"
											, colIndex : "columnName"
											, key : /^((?!(MAPPED_KEY|ROHQCD|MGDPCD|BZSPCD|CNNCD|SCNCD)).|(ROHQCD_NM|MGDPCD_NM|BZSPCD_NM|CNNCD_NM|SCNCD_NM))*$/								
											, condition : "and"
											});

		// GridView 데이터 Filter 설정 - 코드 컬럼 숨김
		var cols = ["rohqcd", "mgdpcd", "bzspcd", "cnncd", "scncd"];
		for (var k=0; k < cols.length; k++) {
			grdDataList1.setColumnVisible(cols[k], false);
		}
	};

	/** 
	 * AS-IS 고정 컬럼(지역본부) 목록을 조회한다.
	 * @param
	 * @return
	 */	
	scwin.retrieveOldHeadquarterList = function() {
		if (dltFixColumns11.getRowCount() == 0) {   // 처음 조회인 경우
			var requestData = {};

			var option = {action : "zz/data/retrieveHeadquarterList.do"
							, reqData : requestData
							, resData : dltFixColumns11
							, success : "scwin.retrieveOldHeadquarterListCallBack"
							, isShowMeg : false
							};
			ajaxLib.executeAjax($p, option);
		}
	};

	/**
	 *  AS-IS 고정 컬럼(지역본부) 목록 조회 CallBack을 실행한다.
	 * @param
	 * @return	 
	 */ 	
	scwin.retrieveOldHeadquarterListCallBack = function(res) {
		if (sbxFixCol11.getRowCount() > 0) {	
			var cd = sbxFixCol11.getValue();
			if (cd != "" && cd != null) {
				scwin.sbxFixCol11_onchange();   // 관리부서 목록 조회
			}
		}
	};

	/** 
	 * AS-IS 고정 컬럼(관리부서) 목록을 조회한다.
	 * @param
	 * @return
	 */	
	scwin.sbxFixCol11_onchange = function() {
		var requestData = {};
		requestData.param = {"rohqcd" : sbxFixCol11.getValue()};   // 지역본부코드

		var option = {action : "zz/data/retrieveDepartmentList.do"
						, reqData : requestData
						, resData : dltFixColumns12
						, success : "scwin.sbxFixCol11CallBack"
						, isShowMeg : false
						};
		ajaxLib.executeAjax($p, option);		
	};

	/**
	 *  AS-IS 고정 컬럼(관리부서) 목록 조회 CallBack을 실행한다.
	 * @param
	 * @return	 
	 */ 	
	scwin.sbxFixCol11CallBack = function(res) {
		scwin.sbxFixCol12_onchange();   // 사업단계 목록 조회
	};

	/** 
	 * AS-IS 고정 컬럼(사업단계) 목록을 조회한다.
	 * @param
	 * @return
	 */	
	scwin.sbxFixCol12_onchange = function() {
		var requestData = {};
		requestData.param = {"mgdpcd" : sbxFixCol12.getValue()};   // 관리부서코드

		var option = {action : "zz/data/retrieveBizStepList.do"
						, reqData : requestData
						, resData : dltFixColumns13
						, success : "scwin.sbxFixCol12CallBack"
						, isShowMeg : false
						};
		ajaxLib.executeAjax($p, option);		
	};

	/**
	 *  AS-IS 고정 컬럼(사업단계) 목록 조회 CallBack을 실행한다.
	 * @param
	 * @return	 
	 */ 	
	scwin.sbxFixCol12CallBack = function(res) {
		scwin.sbxFixCol13_onchange();   // 계통 목록 조회
	};

	/** 
	 * AS-IS 고정 컬럼(계통) 목록을 조회한다.
	 * @param
	 * @return
	 */	
	scwin.sbxFixCol13_onchange = function() {
		var requestData = {};
		requestData.param = {"bzspcd" : sbxFixCol13.getValue()};   // 사업단계코드

		var option = {action : "zz/data/retrieveChannelList.do"
						, reqData : requestData
						, resData : dltFixColumns14
						, success : "scwin.sbxFixCol13CallBack"
						, isShowMeg : false
						};
		ajaxLib.executeAjax($p, option);		
	};

	/**
	 *  AS-IS 고정 컬럼(사업단계) 목록 조회 CallBack을 실행한다.
	 * @param
	 * @return	 
	 */ 	
	scwin.sbxFixCol13CallBack = function(res) {
		scwin.sbxFixCol14_onchange();   // 구간 목록 조회
	};

	/** 
	 * AS-IS 고정 컬럼(구간) 목록을 조회한다.
	 * @param
	 * @return
	 */	
	scwin.sbxFixCol14_onchange = function() {
		var requestData = {};
		requestData.param = {"bzspcd" : sbxFixCol13.getValue()   // 사업단계코드
								  , "cnncd" : sbxFixCol14.getValue()   // 계통코드 
								  };

		var option = {action : "zz/data/retrieveSectionList.do"
						, reqData : requestData
						, resData : dltFixColumns15
						, isShowMeg : false
						};
		ajaxLib.executeAjax($p, option);		
	};

	/** 
	 * AS-IS 테이블 조회를 실행한다.
	 * @param
	 * @return
	 */
	scwin.btnInquire1_onclick = function() {
		if(utilLib.validateGroup(grpSearch1)) {
			var requestData = {};

			dmaInquireParam1.set("selCols", dltColumns1.getColData("columnName").toString());
			requestData.param = dmaInquireParam1.getJSON();

			var option = {action : "zz/data/retrieveDataList.do"
						   , reqData : requestData
						   , resData : dltDataList1
						   , success : "scwin.btnInquire1CallBack"
						   , isShowMeg : false
							 };
			ajaxLib.executeAjax($p, option);
		}
	};

	/** 
	 * AS-IS 테이블 조회 CallBack을 실행한다.
	 * @param <Object> resBody
	 * @return
	 */
	scwin.btnInquire1CallBack = function(resBody) {
		txtCnt1.setValue( "0" );
		if (resBody.message.code == "success") {
			txtCnt1.setValue(dltDataList1.getRowCount());
		} else {
			comLib.alert($p,  "AS-IS 테이블 조회시 에러가 발생되었습니다." );
		}
	};

	/** 
	 * AS-IS 테이블 기준으로 매핑 데이터를 삭제한다.
	 * @param
	 * @return
	 */
	scwin.btnDelete1_onclick = function() {
		var rowIndex1 = grdDataList1.getMatchedIndex("chk1", "1" , true);  // ASIS라디오 선택 index

		if (rowIndex1 != "" && rowIndex1 != null) {
			var mappedKey = dltDataList1.getCellData(rowIndex1 , "mappedKey");  // TOBE 기본키키 - TOBE 기본키
			if (mappedKey == "" || mappedKey == null) {
				comLib.alert($p, "선택한 항목은 매핑되어 있지 않습니다.");
				return;
			}

			var asisPk = dltDataList1.getCellData(rowIndex1 , "pk");  // ASIS 기본키

			dmaSaveData.set("asisTableNm", sbxTables1.getValue());
			dmaSaveData.set("asisColNm", "ASIS_PK");
			dmaSaveData.set("asisColData", asisPk);
		}  else {
			comLib.alert($p, "AS-IS 테이블에서 선택된 데이터가 없습니다.");
			return;
		}

		// 삭제할것인지 confirm
		comLib.confirm($p, "매핑 정보를 삭제하겠습니까?", "delete1Confirm");
	};

	/** 
	 * AS-IS 테이블 기준으로 매핑 데이터를 삭제한다.
	 * @param
	 * @return
	 */
	scwin.delete1Confirm = function() {
		var requestData = {};

		requestData.param = dmaSaveData.getJSON();

		var option = {action : "zz/data/deleteDataMapping.do"
		               , reqData : requestData
		               , success : "scwin.delete1ConfirmCallback"
					   , savedToken : true
		               , isShowMeg : false
	                 };			
		ajaxLib.executeAjax($p, option);	
	};

	/** 
	 * AS-IS 기분 매핑 삭제에 대한 Callback을 실행한다.
	 * @param
	 * @return
	 */
	scwin.delete1ConfirmCallback = function() {
		// AS-IS 매핑 정보 초기화
		var rowIndex1 = grdDataList1.getMatchedIndex("chk1", "1", true);   // ASIS라디오 선택 index
		dltDataList1.setCellData(parseInt(rowIndex1), "mappedKey", "");

		// TO-BE 매핑 정보 초기화
		var asisPk = dltDataList1.getCellData(rowIndex1 , "pk");   // ASIS 기본키
		var arrRowIndex2 = grdDataList2.getMatchedIndex("mappedKey", asisPk, false);   // TOBE 매핑키 index
		for (var k=0; k < arrRowIndex2.length; k++) {
			var mappedKey = dltDataList2.getCellData(arrRowIndex2[k] , "mappedKey");   // TOBE 매핑키
			if (mappedKey != "" && mappedKey != null) {
				dltDataList2.setCellData(arrRowIndex2[k], "mappedKey", mappedKey.replace(asisPk, ""));   // 삭제되는 ASIS기본키 제거
			}
		}	

		comLib.alert($p,  "매핑 정보가 삭제되었습니다." );
	};

	/** 
	 * AS-IS 테이블 기준으로 지도 위치 이동
	 * @param
	 * @return
	 */
	scwin.btnMove_onclick = function() {
		var rowIndex1 = grdDataList1.getMatchedIndex("chk1", "1" , true);  // ASIS라디오 선택 index

		if (rowIndex1 != "" && rowIndex1 != null) {

		}  else {
			comLib.alert($p, "AS-IS 테이블에서 선택된 데이터가 없습니다.");
		}
	};

	/**
	 * TO-BE 테이블 목록을 조회한다.
	 * @param
	 * @return	 
	 */ 	
	scwin.retrieveNewTableList = function() {
		var requestData = {};

		requestData.param = {"tableList" : ["VT_ZZ_VM_PG07012_01"   // PG_모터
												, "VT_ZZ_VM_PG07018_01"   // PG_유량계사양
												, "VT_ZZ_VM_PG07025_01"   // PG_펌프
												, "VT_ZZ_VM_PG07030_01"   // PG_펌프모터밸브
												, "VT_ZZ_VM_PG07037_01"   // PG_인버터
												, "VT_ZZ_VM_PG07049_01"   // PG_측정함
												, "VT_ZZ_VM_PG07053_01"   // PG_커플링
												, "VT_ZZ_VM_PG20004_01"   // PG_건축물
												, "VT_ZZ_VM_PG20027"       // PG_맨홀
												, "VT_ZZ_VM_PG20030"       // PG_유량계위치
												, "VT_ZZ_VM_PG20031_01"   // PG_배류시설위치
												, "VT_ZZ_VM_PG20032_01"   // PG_밸브
												, "VT_ZZ_VM_PG20037_01"   // PG_밸브실
												, "VT_ZZ_VM_PG20048_01"   // PG_서지탱크
												, "VT_ZZ_VM_PG20045_01"   // PG_관로
												, "VT_ZZ_VM_PG20049_01"   // PG_소방시설
												, "VT_ZZ_VM_PG20056_01"   // PG_스탠드파이프
												, "VT_ZZ_VM_PG20060_01"   // PG_펌프모터
												, "VT_ZZ_VM_PG20068_PS"   // PG_측정함위치
												, "VT_ZZ_VM_PG20061_01"   // PG_농축조
												, "VT_ZZ_VM_PG20061_02"   // PG_배슬러지지
												, "VT_ZZ_VM_PG20061_03"   // PG_여과지
												, "VT_ZZ_VM_PG20061_04"   // PG_역세척수조
												, "VT_ZZ_VM_PG20061_05"   // PG_응집지
												, "VT_ZZ_VM_PG20061_06"   // PG_자연건조장
												, "VT_ZZ_VM_PG20061_07"   // PG_정수지
												, "VT_ZZ_VM_PG20061_08"   // PG_조정조
												, "VT_ZZ_VM_PG20061_09"   // PG_집수조
												, "VT_ZZ_VM_PG20061_10"   // PG_착수정
												, "VT_ZZ_VM_PG20061_11"   // PG_침사지
												, "VT_ZZ_VM_PG20061_12"   // PG_침전지
												, "VT_ZZ_VM_PG20061_13"   // PG_혼화지
