	/**
	 * TO-BE 고정 컬럼 설정
	 * @param
	 * @return	 
	 */ 
	scwin.setTobeFixedColumns = function() {
		// 해당 테이블에 고정 컬럼이 포함되어 있지 않으면 SelectBox를 disabled 처리
		// 권역본부
		var idx = dltColumns2.getMatchedIndex("columnName", "DSTRCT_HQ_CD", true);
		if (idx != "" && idx != null) {
			dmaInquireParam2.set("fixColNm1", "DSTRCT_HQ_CD");
			sbxFixCol21.setDisabled(false);	

			// 권역본부 목록 조회
			scwin.retrieveNewHeadquarterList();
		} else {
			dmaInquireParam2.set("fixColNm1", "");
			sbxFixCol21.setDisabled(true);	
		}

		// 관리부서-플랜트번호
		idx = dltColumns2.getMatchedIndex("columnName", "MNGGRP_CD", true); 
		if (idx != "" && idx != null) {
			dmaInquireParam2.set("fixColNm2", "MNGGRP_CD");
			sbxFixCol22.setDisabled(false);	
		} else {
			dmaInquireParam2.set("fixColNm2", "");
			sbxFixCol22.setDisabled(true);	
		}

		// 사업단계
		idx = dltColumns2.getMatchedIndex("columnName", "PM_BSNS_STEP_CD", true);
		if (idx != "" && idx != null) {
			dmaInquireParam2.set("fixColNm3", "PM_BSNS_STEP_CD");
			sbxFixCol23.setDisabled(false);	
		} else {
			dmaInquireParam2.set("fixColNm3", "");
			sbxFixCol23.setDisabled(true);	
		}

		// 계통
		idx = dltColumns2.getMatchedIndex("columnName", "PM_SYST_CD", true);
		if (idx != "" && idx != null) {
			dmaInquireParam2.set("fixColNm4", "PM_SYST_CD");
			sbxFixCol24.setDisabled(false);	
		} else {
			dmaInquireParam2.set("fixColNm4", "");
			sbxFixCol24.setDisabled(true);	
		}

		// 구간
		idx = dltColumns2.getMatchedIndex("columnName", "PM_SCTN_CD", true);
		if (idx != "" && idx != null) {
			dmaInquireParam2.set("fixColNm5", "PM_SCTN_CD");
			sbxFixCol25.setDisabled(false);	
		} else {
			dmaInquireParam2.set("fixColNm5", "");
			sbxFixCol25.setDisabled(true);	
		}
	};

	/**
	 * TO-BE 컬럼 필터 설정
	 * @param
	 * @return	 
	 */ 
	scwin.setTobeColumnFilter = function() {	
		// 조회 조건 컬럼 Filter 설정
		// 첫 번째 컬럼(MAPPED_KEY - 검색하면 속도 느림)과 고정(코드) 컬럼이 검색 조건에서 보이지 않도록 Filter 설정
		dltColumns2.setColumnFilter({type : "regExp"
											, colIndex : "columnName"
											, key : /^((?!(MAPPED_KEY|DSTRCT_HQ_CD|MNGGRP_CD|PM_BSNS_STEP_CD|PM_SYST_CD|PM_SCTN_CD)).|(DSTRCT_HQ_NM|MNGGRP_NM|PM_BSNS_STEP_NM|PM_SYST_NM|PM_SCTN_NM))*$/																
											, condition : "and"
											});

		// GridView 데이터 Filter 설정 - 코드 숨김
		var cols = ["dstrctHqCd", "mnggrpCd", "pmBsnsStepCd", "pmSystCd", "pmSctnCd"];
		for (var k=0; k < cols.length; k++) {
			grdDataList2.setColumnVisible(cols[k], false);
		}											
	};

