	 * @return
	 */
	scwin.btnDelete2_onclick = function() {
		var rowIndex2 = grdDataList2.getMatchedIndex("chk2", "1" , true);  // TOBE 라디오 선택 index

		if (rowIndex2 != "" && rowIndex2 != null) {
			var mappedKey = dltDataList2.getCellData(rowIndex2 , "mappedKey");  // TOBE 매핑키 - ASIS 기본키
			if (mappedKey == "" || mappedKey == null) {
				comLib.alert($p, "선택한 항목은 매핑되어 있지 않습니다.");
				return;
			}

			var tobePk = dltDataList2.getCellData(rowIndex2 , "pk");  // TOBE 기본키

			dmaSaveData.set("tobeTableNm", sbxTables2.getValue());
			dmaSaveData.set("tobeColNm", "TOBE_PK");
			dmaSaveData.set("tobeColData", tobePk);
		}  else {
			comLib.alert($p, "TO-BE 테이블에서 선택된 데이터가 없습니다.");
			return;
		}

		// 삭제할것인지 confirm
		comLib.confirm($p, "매핑 정보를 삭제하겠습니까?", "delete2Confirm");	
	};

