	/** 
	 * TO-BE 매핑 삭제에 대한 Callback을 실행한다.
	 * @param
	 * @return
	 */
	scwin.delete2ConfirmCallback = function() {
		 // TO-BE 매핑 정보 초기화
		var rowIndex2 = grdDataList2.getMatchedIndex("chk2", "1", true);
		dltDataList2.setCellData(parseInt(rowIndex2), "mappedKey", "");

		// AS-IS 매핑 정보 초기화
		var tobePk = dltDataList2.getCellData(rowIndex2 , "pk");  // TOBE 기본키
		var arrRowIndex1 = grdDataList1.getMatchedIndex("mappedKey", tobePk, false);   // ASIS 매핑키 index
		for (var k=0; k < arrRowIndex1.length; k++) {
			var mappedKey = dltDataList1.getCellData(arrRowIndex1[k] , "mappedKey");  // TOBE 매핑키
			if (mappedKey != "" && mappedKey != null) {
				dltDataList1.setCellData(arrRowIndex1[k], "mappedKey", mappedKey.replace(tobePk, ""));   // 삭제되는 TOBE 기본키 제거
			}
		}

		comLib.alert($p,  "매핑 정보가 삭제되었습니다." );
	};

	/** 
	 * AS-IS와 TO-BE 테이블에 대한 키 값을 매핑한다.
	 * @param
	 * @return
	 */
	scwin.btnSave_onclick = function() {
		var asisPk = "";
		var rowIndex1 = grdDataList1.getMatchedIndex("chk1", "1" , true);  // ASIS라디오 선택 index
		if (rowIndex1 != "" && rowIndex1 != null) {
			asisPk = dltDataList1.getCellData(rowIndex1 , "pk");  // ASIS 기본키

			dmaSaveData.set("asisTableNm", sbxTables1.getValue());
			dmaSaveData.set("asisColNm", "ASIS_PK");
			dmaSaveData.set("asisColData", asisPk);
		}  else {
			comLib.alert($p, "AS-IS 테이블에서 선택된 데이터가 없습니다.");
			return;
		}

		var tobePk = "";
		var rowIndex2 = grdDataList2.getMatchedIndex("chk2", "1" , true);  // ASIS라디오 선택 index
		if (rowIndex2 != "" && rowIndex2 != null) {
			tobePk = dltDataList2.getCellData(rowIndex2 , "pk");  // TOBE 기본키

			dmaSaveData.set("tobeTableNm", sbxTables2.getValue());
			dmaSaveData.set("tobeColNm", "TOBE_PK");
			dmaSaveData.set("tobeColData", tobePk);
		}  else {
			comLib.alert($p, "TO-BE 테이블에서 선택된 데이터가 없습니다.");
			return;
		}

		// 기존 매핑 여부 확인
		var mappedKey = dltDataList2.getCellData(rowIndex2 , "mappedKey");   // TOBE 매핑키
		if (mappedKey != "" && mappedKey != null) {
			if (mappedKey.indexOf(asisPk) > -1) {
				comLib.alert($p, "이미 매핑되어 있습니다.");
				return;				
			}
		}			

		// 저장할것인지 confirm
		comLib.confirm($p, "매핑 정보를 저장하겠습니까?", "scwin.saveConfirm");
	};

