	/** 
	 * 매핑 저장에 대한 Callback을 실행한다.
	 * @param
	 * @return
	 */
	scwin.saveConfirmCallback = function() {
		// AS-IS 데이터
		var intRowIdx1 = parseInt(grdDataList1.getMatchedIndex("chk1", "1", true));
		var mappedKey1 = dltDataList1.getCellData(intRowIdx1, "mappedKey");
		var asisPk = dltDataList1.getCellData(intRowIdx1, "pk");

		// TO-BE 데이터
		var intRowIdx2 = parseInt(grdDataList2.getMatchedIndex("chk2", "1", true));
		var mappedKey2 = dltDataList2.getCellData(intRowIdx2, "mappedKey");
		var tobePk = dltDataList2.getCellData(intRowIdx2, "pk");

		// AS-IS 데이터 업데이터
		if (mappedKey1 != "" && mappedKey1 != null) {	
			if (mappedKey1.indexOf(tobePk)  < 0) {   // 매핑되어 있지 않으면
				dltDataList1.setCellData(intRowIdx1, "mappedKey", mappedKey1 + "," + tobePk);
			}
		} else {
			dltDataList1.setCellData(intRowIdx1, "mappedKey", tobePk);
		}

		// TO-BE 데이터 업데이트
		if (mappedKey2 != "" && mappedKey2 != null) {
			if (mappedKey2.indexOf(asisPk)  < 0) {   // 매핑되어 있지 않으면
				dltDataList2.setCellData(intRowIdx2, "mappedKey", mappedKey2 + "," + asisPk);
			}
		} else {
			dltDataList2.setCellData(intRowIdx2, "mappedKey", asisPk);
		}

		comLib.alert($p,  "매핑 정보가 저장되었습니다." );
	};

	/**
	 * GridView의 컬럼을 설정한다.
	 * @param
	 * @return	 
	 */ 	 
	 scwin.setColumnId = function(dataList) {
	 	var num = dataList.id.substr(dataList.id.length-1, 1);   // ex) dltColumns1 --> num=1, dltColumns2 --> num=2
	 	var obj = dataList.getAllJSON();
	 	var column = {};
	 	var columnArr = [];
	 	var gridHeader = "";
	 	var gridBody = "";

	 	gridHeader = '<w2:column inputType="text" id="hChk'+num+'" value="선택" blockSelect="false" width="50" style="height:20px;"></w2:column>';
	 	gridBody = '<w2:column inputType="radio" id="chk'+num+'" radioLabel="&amp;nbsp;" blockSelect="false" width="50" style="height:20px;"></w2:column>';

 	 	// radio 버튼에 대한 DataList 컬럼 추가
 	 	column["id"] = "chk"+num;
	 	column["dataType"] = "text";
	 	columnArr.push(column)

 		// 테이블 컬럼으로 DataList 컬럼 추가								
	 	for (var k=0; k < obj.length; k++) {
	 		column = {};
	 		column["id"] = scwin.camelCase(obj[k].columnName);
	 		column["dataType"] = "text";
	 		columnArr.push(column);

	 		gridHeader += '<w2:column inputType="text" id="'+'h'+column["id"]+'" value="'+obj[k].columnComments+'" blockSelect="false" width="110" style="height:20px;"></w2:column>';
	 		gridBody += '<w2:column inputType="text" id="'+column["id"]+'" readOnly="true" blockSelect="false" width="110" style="height:20px;"></w2:column>';
	 	}

	 	scwin.makeDataList("dltDataList"+num, columnArr);

	 	var gridStr = '<w2:gridView xmlns:w2="http://www.inswave.com/websquare" xmlns:ev="http://www.w3.org/2001/xml-events" id="grdDataList'+num+'"'
	 				+ ' dataList="dltDataList'+num+'" style="height:280px;" sortable="true" focusMode="row" useShiftKey="false" fixedColumn="2" autoFit="lastColumn">'
	 				+ '<w2:header id="header'+num+'" style="">'
	 				+ '<w2:row id="row'+num+'1" style="">'
	 				+ gridHeader
	 				+ '</w2:row>'
	 				+ '</w2:header>'
	 				+ '<w2:gBody id="gBody'+num+'1" style="">'
	 				+ '<w2:row id="row'+num+'2" style="">'
	 				+ gridBody
	 				+ '</w2:row>'
	 				+ '</w2:gBody>'
	 				+ '</w2:gridView>';

		eval("grdDataList"+num).setGridStyle(WebSquare.xml.parse(gridStr, true));
	};	

	/**
	 * DataCollection(DataList)를 동적으로 생성한다.
	 * @param
	 * @return	 
	 */ 	
	scwin.makeDataList = function(id, obj) {
		comLib.createData($p,{
				"id" : id
				, "type" : "dataList"
				, "option" : {	"useData" : "false" }
				, "columnInfo" : obj
		});
	};

	/**
	 * 문자열을 '_'를 기준으로 camelCase로 변경한다. ex) ONE_TWO_THREE -> oneTwoThree
	 * @param
	 * @return	 
	 */ 	
	scwin.camelCase = function(str) {
		return str.toLowerCase().replace(/_([a-z])/g, function(g) {
			return g[1].toUpperCase();
		});
	};
